import { useCallback, useEffect, useState } from 'react';

import { Orientation } from '../../../../../../core/types/orientation.js';
import { ORIENTATION } from '../../../../constants.js';
import { useLegendSize } from '../../shared/context/LegendSizeContext.js';
import {
  CONTAINER_PADDING,
  MAX_LEGEND_HEIGHT,
  MAX_LEGEND_WIDTH,
} from '../constants.js';
import { useOrientation } from '../context/RangeLegendOrientationContext.js';
import { useRangeLegendTruncation } from '../context/RangeLegendTruncationContext.js';
import { handleCollisionInVerticalLayout } from '../utils/handle-collision-in-vertical-layout.js';
import { handleTwoLabelsCollisions } from '../utils/handle-two-labels-collisions.js';
import { getLabelsPosition } from '../utils/labels-collision.js';

/**
 * Hook responsible to detect and resolve the collisions for the boundary labels
 * (only first and last).
 * In the case where a collision is detected, the labels will be modified by
 * adding the text truncation.
 */
export const useLegendBoundaryLabelCollisionDetector = (
  startLabel: string,
  endLabel: string,
) => {
  const [labels, setLabels] = useState({ startLabel, endLabel });
  const truncationMode = useRangeLegendTruncation();
  const { orientation } = useOrientation();
  const { width: legendWidth, height: legendHeight } = useLegendSize();

  const containerLegendHeight = legendHeight - CONTAINER_PADDING * 2;
  const containerLegendWidth = legendWidth - CONTAINER_PADDING * 2;

  const width = Math.min(containerLegendWidth, MAX_LEGEND_WIDTH);
  const height = Math.max(containerLegendHeight, MAX_LEGEND_HEIGHT);

  const handleLabelCollision = useCallback(
    (
      firstLabel: string,
      lastLabel: string,
      orientation: Orientation,
      width: number,
    ): { startLabel: string; endLabel: string } => {
      if (orientation === ORIENTATION.Horizontal) {
        return handleTwoLabelsCollisions(
          firstLabel,
          lastLabel,
          truncationMode,
          [0, width],
        );
      }
      const { startLabel, endLabel } = getLabelsPosition(
        firstLabel,
        lastLabel,
        [0, width],
      );
      const { text: startLabelTruncated } = handleCollisionInVerticalLayout(
        firstLabel,
        startLabel,
        'start',
        truncationMode,
        [0, width],
      );
      const { text: endLabelTruncated } = handleCollisionInVerticalLayout(
        lastLabel,
        endLabel,
        'end',
        truncationMode,
        [0, width],
      );

      return { startLabel: startLabelTruncated, endLabel: endLabelTruncated };
    },
    [truncationMode],
  );

  useEffect(() => {
    if (width <= 0 || height <= 0) {
      return;
    }
    const labelsWithTruncation = handleLabelCollision(
      startLabel,
      endLabel,
      orientation,
      width,
    );
    setLabels({
      startLabel: labelsWithTruncation.startLabel,
      endLabel: labelsWithTruncation.endLabel,
    });
  }, [handleLabelCollision, startLabel, endLabel, orientation, width, height]);

  return labels;
};
